const express = require('express');
const app = express();
const parser = require('xml2js').Parser({
  trim: true,
  normalizeTags: false,
  explicitArray: false,
  mergeAttrs: false,
  attrNameProcessors: [
    function (name) {
      return name.replace(/[^a-z]/gi, '_');
    },
  ],
});
const xml = require('xml2js').parseString;
app.use(express.json()); // to support JSON-encoded bodies
app.post('/upload', async (req, res) => {
  const { body } = req;

  if (!body || !body.xml) return res.status(400).send('No XML provided');

  try {
    await parser.parseStringPromise(body.xml);

    xml(
      body.xml,
      {
        trim: true,
        normalizeTags: false,
        explicitArray: false,
        mergeAttrs: false,
        attrNameProcessors: [
          function (name) {
            return name.replace(/[^a-z]/gi, '_');
          },
        ],
      }
    );

    res.status(200).send('XML parsed and processed successfully.');
  } catch (error) {
    console.log(error);
    res.status(500).send(`Error parsing XML: ${error}`);
  }
});
app.listen(3000, () => {
  console.log('Listening on port 3000');
});